import{a as e,i as t,r as n,t as r}from"./app-DJF5ueEI.js";var i=JSON.parse(`{"path":"/blogs/ebay-connector-for-magento-2.html","title":"eBay Connector for Magento 2 (Adobe Commerce)","lang":"en-US","frontmatter":{},"git":{"updatedTime":1781706203000,"contributors":[{"name":"Mohd Munassir Alam","username":"","email":"munassir.alam632@webkul.in","commits":2},{"name":"Cursor","username":"Cursor","email":"cursoragent@cursor.com","commits":1,"url":"https://github.com/Cursor"}],"changelog":[{"hash":"fec0b4ca4a2ac9add31ec0545055b0e7503c7108","time":1781706203000,"email":"munassir.alam632@webkul.in","author":"Mohd Munassir Alam","message":"Updated Blog MD files"},{"hash":"7f690eb6836c870c0b97ce711d51fcb9cd13c124","time":1781695993000,"email":"munassir.alam632@webkul.in","author":"Mohd Munassir Alam","message":"Add Webkul Magento 2 documentation site with VuePress.","coAuthors":[{"name":"Cursor","email":"cursoragent@cursor.com"}]}]},"filePathRelative":"blogs/ebay-connector-for-magento-2.md"}`),a={name:`ebay-connector-for-magento-2.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="ebay-connector-for-magento-2-adobe-commerce" tabindex="-1"><a class="header-anchor" href="#ebay-connector-for-magento-2-adobe-commerce"><span>eBay Connector for Magento 2 (Adobe Commerce)</span></a></h1><p>Updated 17 June 2026</p><p><a href="https://magento2demo.webkul.in/ebayconnector/?demo=Webkul_Ebaymagentoconnect" target="_blank" rel="noopener noreferrer">Live Demo</a></p><p><a href="https://store.webkul.com/magento2-ebay-connector.html" target="_blank" rel="noopener noreferrer">eBay Connector for Magento 2</a> (Adobe Commerce) allows you to seamlessly integrate your Magento 2 store with eBay.</p><p>Import products, categories, orders, shipping details, and product attributes from eBay to Magento 2.</p><p>The admin can also export products from Magento 2 to eBay, automate product synchronization, manage category mapping, and streamline catalog management across both platforms.</p><p>Hence, the admin can efficiently manage eBay and Magento operations from a single centralized interface.</p><p>Check a brief overview of the plugin’s initial configuration settings –</p><p>6gV0ll1amrY</p><p>Check a brief overview of the plugin’s management options available to the admin –</p><p>RyvEobbc5EM</p><h2 id="features-of-ebay-connector-for-magento-2-adobe-commerce" tabindex="-1"><a class="header-anchor" href="#features-of-ebay-connector-for-magento-2-adobe-commerce"><span>Features Of eBay Connector for Magento 2 (Adobe Commerce)</span></a></h2><ul><li>Import eBay products, orders, and categories into Magento 2 with automatic category creation and mapping options.</li><li>Export products from Magento 2 to the eBay store manually or automatically.</li><li>Import Simple and Configurable product types.</li><li>Export Simple, Configurable, Bundle, and Grouped product types.</li><li>Import products by SKU, listing ID, or end listing date range.</li><li>Import only active products and filter products based on stock status and price range.</li><li>Export products using SKU and price-based filters.</li><li>Synchronize product conditions, specifications, variations, dimensions, weight, shipping costs, and attributes.</li><li>Auto-map Magento SKU to eBay MPN and Magento Brand to eBay Brand.</li><li>Support eBay-specific product titles and product images during export.</li><li>Real-time order and inventory synchronization through eBay webhooks.</li><li>Auto-update shipping and tracking information on eBay in real time.</li><li>Configure shipping details and product-level shipping costs for exported products.</li><li>Configure return policy details and listing duration for export products.</li><li>Create and manage eBay listing templates.</li><li>Set default sync category, order status, quantity, website, and store view.</li><li>Export products to eBay using mapped eBay store categories.</li><li>Automatic category creation and mapping based on matching category structures.</li><li>Automatic weight unit conversion during product synchronization.</li><li>Bulk product export using eBay Feed API with export queue and task monitoring.</li><li>Sandbox mode available for testing and development.</li><li>Revise imported eBay product details from Magento.</li><li>Supports package dimension attribute mapping.</li><li>Supports multiple language translations.</li><li>Admin can configure pricing rules for imported and exported products.</li><li>Aria2c integration for faster product image downloads.</li><li>Magento CSV Model implementation for faster product imports.</li><li>Open-source code available for customization and extension.</li></ul><h2 id="installation-of-ebay-connector-for-magento-2" tabindex="-1"><a class="header-anchor" href="#installation-of-ebay-connector-for-magento-2"><span>Installation Of eBay Connector for Magento 2</span></a></h2><p>Customers will get a <strong>zip folder</strong> and they have to extract the contents of this zip folder on their system. Thus, the extracted folder has an ** src** folder, inside the src folder you have the <strong>app</strong> folder.</p><p>You need to transfer this <strong>app</strong> folder into the Magento2 root directory on the server as shown below.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2023/09/magento2-folder-structure.webp" alt="magento2-folder-structure"></p><p>If you download the module from Magento Connect then unzip the respective extension zip.</p><p>Henceforth create <strong>Webkul</strong>(vendor) then <strong>Ebaymagentoconnect</strong>(module) name folder inside your magento2 root directory as:</p><p><strong>app/code/Webkul/Ebaymagentoconnect</strong> and then move all module’s files inside <strong>/app/code/Webkul/Ebaymagentoconnect/</strong> folder in magento2 root directory.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2023/09/ebay-magento-connector-folder-structure.webp" alt="ebay-magento-connector-folder-structure"></p><p>After the upload, you can see the folders in your Magento2 Root Directory.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2023/09/ebay-magento-connector-folder-struscture.webp" alt="ebay-magento-connector-folder-struscture"></p><p>Hereafter the successful installation, you have to run these commands in the Magento2 root directory.</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">composer require webkul/ebayconnector</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">php bin/magento setup:upgrade</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">php bin/magento setup:di:compile</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">php bin/magento setup:static-content:deploy</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">php bin/magento indexer:reindex</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">php bin/magento cache:flush</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>Note- “composer require webkul/ebayconnector”</strong> this command is necessary to run in the terminal for the proper installation of the module.</p><h2 id="multilingual-support" tabindex="-1"><a class="header-anchor" href="#multilingual-support"><span>Multilingual Support</span></a></h2><p>For **multilingual **support, the admin will navigate through <strong>Store-&gt;Configuration-&gt;General -&gt;Locale Options.</strong></p><p>Hence, select the locale as German (the language into which the admin wants to translate his store content).</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2019/10/magento2-german-admin-configuration-locale.webp" alt="magento2-german-admin-configuration-locale"></p><h2 id="translation-of-ebay-connector-for-magento-2" tabindex="-1"><a class="header-anchor" href="#translation-of-ebay-connector-for-magento-2"><span>Translation Of eBay Connector for Magento 2</span></a></h2><p>If a user wants to translate their module from English to German. Henceforth, they need to follow the path <strong>app/code/Webkul/Ebaymagentoconnect/i18n</strong> in their unzip Magento2 Ebaymagentoconnect folder.</p><p>The user receives a CSV file with the name “en_US.csv”. Now they will rename that CSV as “de_DE.csv”.</p><p>Then translate all right side content after the comma in the German language.</p><p>After editing the CSV, save it and then upload it to the path <strong>app/code/Webkul/Ebaymagentoconnect/i18n</strong> where the Magento2 on the server installation took place.</p><p>So, the module will translate into the German Language. However, it supports both **RTL **and **LTR **languages.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2023/09/ebay-magento-connector-multi-language-csv.webp" alt="ebay-magento-connector-multi-language-csv"></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2023/09/multi-language-csv.webp" alt="multi-language-csv"></p><p>Thus, the user can edit the CSV like the image below.<br><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/Screenshot-from-2018-04-23-17-33-44.png" target="_blank" rel="noopener noreferrer">![eBay Connector for Magento2 image](https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/Screenshot-from-2018-04-23-17-33-44.png)</a></p><h2 id="ebay-connector-for-magento2-configuration" tabindex="-1"><a class="header-anchor" href="#ebay-connector-for-magento2-configuration"><span>eBay Connector for Magento2 Configuration</span></a></h2><h3 id="how-to-get-ebay-connector-credentials" tabindex="-1"><a class="header-anchor" href="#how-to-get-ebay-connector-credentials"><span>How to get eBay Connector credentials?</span></a></h3><p>After the successful installation of\xA0Magento 2 ebay integration module, one will need to fill in the eBay developer keys <strong>(app id, cert id, dev id, user id, auth token</strong>).</p><p>Thus, the eBay account has these credentials.</p><p>However, if the user doesn’t have an account, then the user will have to create an account and get the required keys.</p><h4 id="first-step" tabindex="-1"><a class="header-anchor" href="#first-step"><span><strong>First Step</strong></span></a></h4><p>To create a new account go to <a href="https://developer.ebay.com" target="_blank" rel="noopener noreferrer"><strong>developer.ebay.com</strong></a> and click on the <strong>sign-in/Join link</strong>.</p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2014/02/Sign-Up.png" target="_blank" rel="noopener noreferrer">![Sign-Up](https://cdnblog.webkul.com/blog/wp-content/uploads/2014/02/Sign-Up.png)</a></p><h4 id="second-step" tabindex="-1"><a class="header-anchor" href="#second-step"><span><strong>Second Step</strong></span></a></h4><p>Now, create a <strong>username</strong> and <strong>password</strong> for your account and then click the <strong>join</strong> button.<br><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2014/02/Register.png" target="_blank" rel="noopener noreferrer">![Register- eBay Connector for Magento2](https://cdnblog.webkul.com/blog/wp-content/uploads/2014/02/Register.png)</a></p><h4 id="third-step" tabindex="-1"><a class="header-anchor" href="#third-step"><span>Third Step</span></a></h4><p>After the above step, you need to create an app. Enter the <strong>app name</strong> and choose the <strong>environment</strong> to generate your <strong>key set</strong>.</p><p>So, keep a note that when you generate the keys set then only the app saves.</p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2014/02/App-name.pnge" target="_blank" rel="noopener noreferrer">![eBay Connector for Magento 2](https://cdnblog.webkul.com/blog/wp-content/uploads/2014/02/App-name.png)</a></p><h4 id="fourth-step" tabindex="-1"><a class="header-anchor" href="#fourth-step"><span><strong>Fourth Step</strong></span></a></h4><p>So, after clicking on the <strong>Create a Keyset</strong> link(for the environment you choose), you need to confirm the primary contact for this account first.</p><p>Henceforth you can click the <strong>Continue to Create Keys</strong> button.<br><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2014/02/confirm-primary-Account-1.png" target="_blank" rel="noopener noreferrer">![confirm-primary-Account eBay Connector for Magento2](https://cdnblog.webkul.com/blog/wp-content/uploads/2014/02/confirm-primary-Account-1.png)</a></p><h4 id="fifth-step" tabindex="-1"><a class="header-anchor" href="#fifth-step"><span>Fifth Step</span></a></h4><p>Now you can see the environment key that you select. Thus, for creating the production keys just click on the “<strong>Create a Key Set</strong>” and you will get your production keys.<br><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2014/02/Sandbox-keys.png" target="_blank" rel="noopener noreferrer">![Sandbox-keys-eBay Connector for Magento2](https://cdnblog.webkul.com/blog/wp-content/uploads/2014/02/Sandbox-keys.png)</a></p><h4 id="sixth-step" tabindex="-1"><a class="header-anchor" href="#sixth-step"><span><strong>Sixth Step</strong></span></a></h4><p>Thus, for generating the <strong>User Token</strong> go to your <strong>Application keys page</strong>. Hence, in the <strong>App ID</strong> row of the Sandbox keyset, click the <strong>User Tokens</strong> to access the Tokens page for your Sandbox keyset.<br><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2014/02/Sandbox-keys-1.png" target="_blank" rel="noopener noreferrer">![image](https://cdnblog.webkul.com/blog/wp-content/uploads/2014/02/Sandbox-keys-1.png)</a></p><h4 id="seventh-step" tabindex="-1"><a class="header-anchor" href="#seventh-step"><span>Seventh ** Step**</span></a></h4><p>After you click on <strong>“User Tokens”</strong> in the snapshot above, you will see a “<strong>Sign in to Sandbox</strong>” button. Hence, click it to access the sandbox account.<br><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2014/02/Sign-In-Sandbox.png" target="_blank" rel="noopener noreferrer">![image](https://cdnblog.webkul.com/blog/wp-content/uploads/2014/02/Sign-In-Sandbox.png)</a></p><p>So, from here, the user can even get an ‘<strong>eBay Oauth Key</strong>‘ which they can add to <strong>Default Business Policy</strong>.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/User-Tokens-eBay-Sign-In-eBay-1-1.png" alt="User-Tokens-eBay-Sign-In-eBay-1-1"></p><p>Here, the ‘<em>sjohn_smith-johnsmit-john-laitazrqx</em>‘ is the RuName of the application that will be part of the admin configuration.</p><p>Additionally, the Your privacy policy URL, auth accepted URL and auth declined URL- will have the frontend URL of the website.</p><p><strong>Your auth accepted URL:</strong> This field is the most important. It should be set as shown below-</p><p>https://<strong>domainname</strong>/ebaymagentoconnect/index/fetchtoken</p><h4 id="eighth-step" tabindex="-1"><a class="header-anchor" href="#eighth-step"><span><strong>Eighth</strong> Step</span></a></h4><p>Now, enter your Sandbox <strong>Username</strong> and <strong>Password</strong>.<br><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2014/02/login-sandbox.png" target="_blank" rel="noopener noreferrer">![image](https://cdnblog.webkul.com/blog/wp-content/uploads/2014/02/login-sandbox.png)</a></p><h4 id="ninth-step" tabindex="-1"><a class="header-anchor" href="#ninth-step"><span>Ninth Step</span></a></h4><p>Hence, after clicking the “<strong>Sign in</strong>” button, you will see another page where you have to click the “<strong>Agree</strong>” button.</p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2014/02/Agree.png" target="_blank" rel="noopener noreferrer">![image](https://cdnblog.webkul.com/blog/wp-content/uploads/2014/02/Agree.png)</a></p><h4 id="tenth-step" tabindex="-1"><a class="header-anchor" href="#tenth-step"><span>Tenth Step</span></a></h4><p>Lastly, you will redirect back and will get the <strong>App Token</strong>.<br><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2014/02/App-Token.png" target="_blank" rel="noopener noreferrer">![App-Token-eBay Connector for Magento2](https://cdnblog.webkul.com/blog/wp-content/uploads/2014/02/App-Token.png)</a></p><h3 id="ebay-magento-connect-configuration" tabindex="-1"><a class="header-anchor" href="#ebay-magento-connect-configuration"><span>eBay Magento Connect Configuration</span></a></h3><p>Now you can proceed to the admin configuration part where you need to fill in the configuration details.</p><p>The admin shall navigate through\xA0<strong>Store &gt; Configuration &gt; eBay Magento Connect</strong>\xA0in the admin panel and set the configurations for Magento 2 eBay Connector.</p><p>Thus, the admin will configure the settings for the following configuration sections:</p><ul><li>General Settings</li><li>Real-Time Information Update</li><li>Store Settings</li><li>Return Policy</li><li>Listing Options</li><li>Dispatch Options</li><li>Payment Options</li><li>Package Information</li><li>Order Sync Option</li><li>Default Settings for eBay Product Import</li><li>Default business Policy</li></ul><p><strong>General Settings</strong></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/Configuration-Settings-Stores-Magento-Admin-2.png" alt="Configuration-Settings-Stores-Magento-Admin-2"></p><p><em><strong>Fields</strong></em></p><ul><li>Attribute Set ID – Select the default attribute to synchronize products.</li><li>Global Sites – Select your eBay store according to the region or country.</li><li>eBay- <ul><li>User Id – Enter the eBay login user name here.</li><li>Authentication Token – Enter the eBay user token which gets creates.</li><li>Developer Token – Enter Dev ID here.</li><li>Application Id – Enter App ID here.</li><li>Certification Id – Enter Cert ID here.</li></ul></li><li>Application RuName – It is retrieved from the Get a Token from eBay via Your Application in eBay account.</li><li>Mode – Two modes are available, Sandbox mode is for testing purposes and Production mode for the live purpose.</li><li>Item Country – Select the country for products.</li><li>Item Location –\xA0 Enter the location of your product.</li><li>Shop’s Postal Code – Enter your eBay store zip code.</li></ul><h4 id="real-time-information-update" tabindex="-1"><a class="header-anchor" href="#real-time-information-update"><span><strong>Real-Time</strong>** Information Update**<img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/real-time.png" alt="real-time"></span></a></h4><p><em><strong>Real-Time Information Update Fields</strong></em></p><p><strong>Subscribe eBay Events</strong></p><ul><li>The admin can select which eBay Event can be synced from eBay to Magento2.</li><li>That is an event among items sold, created, revised, close, and fix price transactions that will take place on eBay and will sync and reflect on the Magento2 store.</li></ul><p><strong>Sold Item Action-</strong> The admin can select Order Creation and Inventory Management or only Inventory Management as the action that will take place on the Magento2 store when an item is sold on eBay.</p><ul><li>Order Creation and Inventory Management- This will create an order and deduct the quantity in the inventory as the item is sold on the eBay store.</li><li>Only Inventory Management- This will only deduct the quantity in the inventory on the Magento2 store as the item on the eBay store.</li></ul><h4 id="store-settings-image-https-cdnblog-webkul-com-blog-wp-content-uploads-2016-03-configuration-settings-stores-magento-admin-1-png" tabindex="-1"><a class="header-anchor" href="#store-settings-image-https-cdnblog-webkul-com-blog-wp-content-uploads-2016-03-configuration-settings-stores-magento-admin-1-png"><span><strong>Store Settings</strong><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/Configuration-Settings-Stores-Magento-Admin-1.png" target="_blank" rel="noopener noreferrer">![image](https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/Configuration-Settings-Stores-Magento-Admin-1.png)</a></span></a></h4><p><em><strong>Store Settings Fields</strong></em></p><ul><li>Revise eBay item automatically on eBay Store – Select ‘Yes’ in order to revise eBay item, automatically, whenever an item gets an update on the Magento store, else select ‘No’ option.</li><li>eBay item import with specification\xA0– Here admin can select either All or Required. If the admin selects ‘All’ then it will import all the eBay product specifications. <ul><li>Otherwise, if the admin chooses ‘Required’ then it will import only require specifications (that is, the fields marked as required) on eBay to the Magento store.</li></ul></li></ul><h4 id="returns-policy" tabindex="-1"><a class="header-anchor" href="#returns-policy"><span><strong>Returns Policy</strong></span></a></h4><h4 id="magento2-ebay-connector-https-cdnblog-webkul-com-blog-wp-content-uploads-2019-03-webkul-magento2-ebay-connector-return-policy-png" tabindex="-1"><a class="header-anchor" href="#magento2-ebay-connector-https-cdnblog-webkul-com-blog-wp-content-uploads-2019-03-webkul-magento2-ebay-connector-return-policy-png"><span><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2019/03/webkul-magento2-ebay-connector-return-policy.png" target="_blank" rel="noopener noreferrer">![magento2 ebay connector](https://cdnblog.webkul.com/blog/wp-content/uploads/2019/03/webkul-magento2-ebay-connector-return-policy.png)</a></span></a></h4><p><em><strong>Return Policy Fields</strong></em></p><ul><li><ul><li>Define Return Policy – Select Returns Accepted or Not Accepted from the dropdown list. This option is for the product which is exported.</li><li>Returns within – Select the return duration for the exported products such as 14, 30 or 60 days.</li><li>Return Shipping Pay By – Chose from the list whether Seller or Buyer shall be paying for the product returned.</li><li>Refund Option – Choose either Money Back or Money Back or Replacement from the given list as a Refund Option.</li><li>Other Information\xA0–\xA0Write any additional information about Return Policy for the exported products.</li></ul></li></ul><h4 id="listing-options" tabindex="-1"><a class="header-anchor" href="#listing-options"><span><strong>Listing Options</strong></span></a></h4><h5 id="" tabindex="-1"><a class="header-anchor" href="#"><span><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/listing-options.png" alt="listing-options"></span></a></h5><ul><li>Listing Duration – Select Good Till Canceled, 1, 3, 5, 7, 10 or 30 days. It is\xA0the duration of exported products on eBay.</li><li>Gallery Type – Admin can select the Gallery type as – Normal or Plus. If chosen Plus for Gallery type, a listing is highlighted with a large gallery photo on the search results page. <ul><li>However, if Normal is chosen for gallery type, the gallery image of the listing is included in the search results page and is free of cost.</li></ul></li></ul><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/listing_options_gallerytype.png" alt="listing_options_gallerytype"></p><ul><li><ul><li>If Normal is selected, then the product while being exported will not have this option\xA0(as shown in the above image) checked. Else if Plus is selected then the option will be auto-selected while exporting the product to eBay.</li></ul></li><li>Use Templates For Listing – The admin can select “yes” to\xA0enable the template listing to export the product’s additional information along with the product. Else select “no” to disable template listing.</li><li>Select Template – The admin can select the template. As per the selected template, the\xA0additional information will get exported along with the product.</li><li>eBay Price Rule Applicable For–The admin can choose to apply price rule on import product, export product or go with none option to remain the price rule unapplied.</li><li>Product Type For Export-\xA0The admin can select from here the type of product that will be exported to eBay.</li><li>Add SubTitle on eBay Product: Either Yes or No can be chosen for this field. It simplifies the search as it shall appear as a keyword to the buyers when they are searching for a product.</li></ul><h4 id="dispatch-options" tabindex="-1"><a class="header-anchor" href="#dispatch-options"><span><strong>Dispatch Options:</strong></span></a></h4><p>The admin will have to set the configurations for the Dispatch Time field under dispatch options.</p><p>Against the Dispatch Time field, the admin needs to select the dispatch time for exported products on eBay such as 1, 2, 3, 4 days.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/module-configuration-dispatch.png" alt="image"></p><h4 id="payment-options-payment-option-ebay-connector-for-magento2-https-cdnblog-webkul-com-blog-wp-content-uploads-2016-03-configuration-settings-stores-magento-adminpayment-png-fields" tabindex="-1"><a class="header-anchor" href="#payment-options-payment-option-ebay-connector-for-magento2-https-cdnblog-webkul-com-blog-wp-content-uploads-2016-03-configuration-settings-stores-magento-adminpayment-png-fields"><span><strong>Payment Options</strong><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/Configuration-Settings-Stores-Magento-Adminpayment.png" target="_blank" rel="noopener noreferrer">![payment_option-eBay Connector for Magento2](https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/Configuration-Settings-Stores-Magento-Adminpayment.png)</a>*** Fields-***</span></a></h4><ul><li><p>Paypal Email Address – Enter your PayPal email ID.</p></li><li><p>Default Category – When the eBay category is not mapped with Magento then products will assign to this category.</p></li><li><p>Store Currency – \xA0Select your eBay store currency.</p></li><li></li></ul><h2 id="shipping-information-on-exported-products" tabindex="-1"><a class="header-anchor" href="#shipping-information-on-exported-products"><span>Shipping Information On Exported Products</span></a></h2><p>As the product gets exported to the eBay end, the following shipping information also gets exported to eBay along with the product.</p><p>Some of the following details that get exported are mentioned below like:-</p><ul><li>Shipping &amp; Handling charges,</li><li>Shipping service,</li><li>Custom shipping duration for minimum and maximum limits can be set in the number of days by the admin,</li><li>Additional Shipping Amount if the customer purchases additional quantities.</li></ul><p><strong>Note</strong>:-\xA0 When the products get imported from eBay to Magento 2 end, then no shipping information comes up with the product.</p><p>However, only the standard available shipping methods available at the Magento store &amp; are visible to the customer during the checkout process.</p><h4 id="package-information" tabindex="-1"><a class="header-anchor" href="#package-information"><span>Package Information</span></a></h4><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/Configuration_Settings_Stores_Magento_Admin-2-1.png" alt="Configuration_Settings_Stores_Magento_Admin-2-1"></p><p>***Package Information Fields-\xA0***</p><ul><li>Shipping Package Type: The admin may select any of the given options- Package/thick envelope, large envelope, Letter, or Large Package, whichever is feasible.</li><li>Irregular Package: Can be chosen as Yes or No. This field shall notify the carrier that this package requires special handling.</li><li>Measurement Unit: The admin can select either of the two-unit types to measure weight and dimensions- English System of Measurement, or Metric System of Measurement.</li></ul><h4 id="order-sync-option-ebay-connector-for-magento2-https-cdnblog-webkul-com-blog-wp-content-uploads-2019-03-webkul-magento2-ebay-connector-order-sync-png" tabindex="-1"><a class="header-anchor" href="#order-sync-option-ebay-connector-for-magento2-https-cdnblog-webkul-com-blog-wp-content-uploads-2019-03-webkul-magento2-ebay-connector-order-sync-png"><span><strong>Order Sync Option</strong><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2019/03/webkul-magento2-ebay-connector-order-sync.png" target="_blank" rel="noopener noreferrer">![eBay Connector for Magento2](https://cdnblog.webkul.com/blog/wp-content/uploads/2019/03/webkul-magento2-ebay-connector-order-sync.png)</a></span></a></h4><p><strong>Order Sync Option Fields:</strong></p><ul><li>Default store view for order sync – Select the default store view for order sync.</li><li>eBay Imported Order Status – Set default order status for the order which imported from eBay.</li><li>Default Product Quantity – Set default product quantity for a product which exported to eBay if product quantity is zero in the store.</li><li>eBay Import Order: Select the order status from the given list. The orders bearing the selected status shall be imported from eBay.</li></ul><h4 id="default-setting-for-ebay-product-import" tabindex="-1"><a class="header-anchor" href="#default-setting-for-ebay-product-import"><span><strong>Default Setting For eBay Product Import</strong></span></a></h4><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/Configuration_Settings_Stores_Magento_Admin-2.png" alt="Configuration_Settings_Stores_Magento_Admin-2"></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2023/09/defaultsetting.webp" alt="defaultsetting"></p><p><em><strong>Fields-</strong></em></p><ul><li>Product import limitation according to mapped categories– You can select the import limitation into Yes/no for mapped categories.</li><li>Default Website- The selected website under Default Website will be assigned to all eBay products by default.</li><li>Default Source-\xA0 You can select Default Source or Not Assigned, selected Source will be assigned to all eBay products by default.</li><li>Product Description with HTML- Product import in-store with HTML description content.</li><li>Default Tax Class- Select the tax class from the dropdown which will then be assigned to all eBay products by default.</li><li>Enable Message Queue- If set to Yes, then the event notification will work with message queue and product images will be imported with the help of message queue.</li><li>Product Import with Images- The product images will be imported along with products if this option is set to Yes.</li><li>Import Out-of-Stock Products – Select Yes to import and export out-of-stock eBay products. Select No to exclude them from import and export.</li><li>Product Price Range From – Enter the minimum product price to include during product import and export.</li><li>Product Price Range To – Enter the maximum product price to include during product import and export.</li></ul><h3 id="automatic-product-export-to-ebay-fields" tabindex="-1"><a class="header-anchor" href="#automatic-product-export-to-ebay-fields"><span>Automatic Product Export To eBay Fields</span></a></h3><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2023/09/automaticproductexporttoebay.webp" alt="automaticproductexporttoebay"></p><ul><li>Enable Auto Export – Select Yes to automatically export products from mapped categories to eBay using cron jobs.</li><li>Max Products Per Cron Run – Enter the maximum number of products that can be queued for export during a single cron execution.</li><li>Dry Run Mode – Select Yes to log eligible products without exporting them. Use this to verify export behavior.</li><li>Use Bulk Feed API – Select Yes to export products in batches using the eBay Sell Feed API instead of the standard queue.</li><li>Bulk Feed Batch Size – Specify the number of products to include in each bulk export feed submitted to eBay.</li><li>Feed Schema Version – Enter the eBay feed schema version to be used when generating bulk export files.</li></ul><h3 id="automatic-product-export-to-ebay-fields-1" tabindex="-1"><a class="header-anchor" href="#automatic-product-export-to-ebay-fields-1"><span>Automatic Product Export To eBay Fields</span></a></h3><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2023/09/automaticproductexport.webp" alt="
automaticproductexport"></p><ul><li>Enable Auto Export – Select Yes to automatically export products from mapped categories to eBay.</li><li>Max Products Per Cron Run – Set the maximum number of products to queue for export during each cron run.</li><li>Dry Run Mode – Select Yes to log eligible products without exporting them to eBay.</li><li>Use Bulk Feed API – Select Yes to export products in bulk using the eBay Sell Feed API.</li><li>Bulk Feed Batch Size – Set the number of products to include in each bulk export feed file.</li><li>Feed Schema Version – Enter the eBay feed schema version used to generate export feed files.</li></ul><h4 id="default-business-policy" tabindex="-1"><a class="header-anchor" href="#default-business-policy"><span>Default Business Policy</span></a></h4><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2019/03/webkul-magento2-ebay-connector-default-business-policy.png" target="_blank" rel="noopener noreferrer">![eBay Connector for Magento2_default business policy](https://cdnblog.webkul.com/blog/wp-content/uploads/2019/03/webkul-magento2-ebay-connector-default-business-policy.png)</a></p><h5 id="fields" tabindex="-1"><a class="header-anchor" href="#fields"><span><em><strong>Fields-</strong></em></span></a></h5><ul><li>Business Profile Enabled on eBay: Choose Yes or No so as to display or not display business profile on eBay.</li><li>eBay Marketplace: Choose the eBay marketplace from the given list of options.</li><li>Payment Policy: Retrieved from eBay after signing in using the selected eBay Marketplace.</li><li>Shipping Policy:\xA0Retrieved from eBay after signing in using the selected eBay Marketplace.</li><li>Return Policy:\xA0Retrieved from eBay after signing in using the selected eBay Marketplace.</li></ul><h3 id="ebay-product-shipping-carrier-configuration" tabindex="-1"><a class="header-anchor" href="#ebay-product-shipping-carrier-configuration"><span>eBay Product Shipping Carrier Configuration</span></a></h3><p>Navigate to <strong>Stores &gt; Configuration &gt; Sales &gt; Delivery Methods &gt; eBay Product Shipping</strong> to configure the shipping method.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2023/09/ebayproductshippingcarrier.webp" alt="ebayproductshippingcarrier"></p><ul><li>Enabled – Select Yes to enable the eBay Product Shipping method on the storefront checkout.</li><li>Title – Enter the title to display for the eBay shipping carrier at checkout.</li><li>Method Name – Enter the shipping method name that customers will see during checkout.</li><li>Ship to Applicable Countries – Choose whether to offer this shipping method for all allowed countries or specific countries.</li><li>Ship to Specific Countries – Select the countries where customers can use this shipping method.</li><li>Sort Order – Set the display order of this shipping method among other available shipping methods.</li><li>Displayed Error Message – Enter the message to show when this shipping method is unavailable for an address.</li></ul><p><strong>Note:</strong> The module imports eBay shipping details such as shipping charges, delivery duration, and handling information with products.</p><p>It uses the synced shipping cost to calculate shipping charges at Magento checkout when the eBay Product Shipping method is enabled.</p><h2 id="ebay-magento-connect-menu" tabindex="-1"><a class="header-anchor" href="#ebay-magento-connect-menu"><span>eBay Magento Connect menu</span></a></h2><p>The **eBay Magento Connect <strong>includes the following Dashboard Options once the admin successfully installs the eBay Connector for the Magento2 module. The admin can ** Map:</strong></p><ul><li>Category</li><li>Category Automation</li><li>Product</li><li>eBay Order</li><li>Export Queue Log</li><li>Bulk Export Tasks</li><li>Listing Templates</li><li>Price Rules</li><li>Real-Time Missed Orders, and</li><li>Configuration</li></ul><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2023/09/ebaymagentoconnect-1.webp" alt="magento2_Ebaymagentoconnectorebaymagentoconnect"></p><h3 id="map-category-ebay-connector-for-magento2" tabindex="-1"><a class="header-anchor" href="#map-category-ebay-connector-for-magento2"><span>Map Category- eBay Connector for Magento2</span></a></h3><p>After importing all the eBay categories you need to map them to store categories.</p><p>At the time of mapping, eBay Condition, and Specification will be created as product attributes and eBay variations will be created as Super Attributes (used for configurable products) in Magento 2.</p><p>The admin can map category, under the <strong>eBay Magento Connector &gt; Map Category</strong> option like the image below.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/Mapped-Categories-List-eBay-Magento-Connect-Magento-Admin-3.png" alt="Mapped-Categories-List-eBay-Magento-Connect-Magento-Admin-3"></p><p>View mapped categories with EAN, UPC, and eBay Store Category. Admin clicks “Map Category” to open a new page. Only one sub-category can be mapped at a time; parent categories aren’t allowed.</p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/Category-Mapping.png" target="_blank" rel="noopener noreferrer">![image](https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/Category-Mapping.png)</a></p><p><strong>Note:</strong>\xA0 If the admin has created any store on the eBay then, an additional field\xA0<strong>“eBay Store Category”</strong> will be visible. Thus, for that store, you might have created certain custom categories also.</p><p>This <strong>“eBay Store Category”</strong> field will display those custom categories for mapping.</p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/Map-Category.png" target="_blank" rel="noopener noreferrer">![mapping](https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/Map-Category.png)</a></p><h3 id="ebay-category-automation-results" tabindex="-1"><a class="header-anchor" href="#ebay-category-automation-results"><span>eBay Category Automation Results</span></a></h3><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2023/09/categoryautomation-1.webp" alt="magento2_Ebaymagentoconnectorcategoryautomation"></p><h4 id="search-filter-fields" tabindex="-1"><a class="header-anchor" href="#search-filter-fields"><span>Search Filter Fields</span></a></h4><p><strong>eBay Parent Category</strong> – Select an eBay parent category to load and filter related eBay categories.</p><p><strong>Mode</strong> – Choose <strong>Create + Auto Map</strong> to create and map categories automatically, or <strong>Create Only</strong> to create categories without mapping.</p><p><strong>Attribute Set</strong> – Select the attribute set to assign to the Magento categories created during automation.</p><p><strong>Overwrite Existing Mapping</strong> – Select this option to replace existing category mappings with new mappings.</p><p><strong>Load Real-Time eBay Categories</strong> – Click to fetch the latest category hierarchy directly from eBay.</p><p><strong>Run for Selected Categories</strong> – Select the required leaf eBay subcategories and click this button to create and map them in Magento.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2023/09/categoryautomation-2.webp" alt="magento2_Ebaymagentoconnectorcategoryautomation"></p><h4 id="category-listing" tabindex="-1"><a class="header-anchor" href="#category-listing"><span>Category Listing</span></a></h4><p>Use the search field to find categories by ID, name, or path. Select leaf categories from the grid and run the automation process.</p><p><strong>Note:</strong> The module creates the Magento category hierarchy from eBay categories and can automatically map matching categories to reduce manual configuration.</p><h3 id="map-product" tabindex="-1"><a class="header-anchor" href="#map-product"><span>Map Product</span></a></h3><p>The admin can synchronize its products on both the stores with the help of this eBay connector extension.</p><p>Admin can import products from ebay to Magento 2 and from Magento 2 to ebay.</p><p>So, given below are the steps for Product Mapping.</p><h3 id="_1-import-product-from-ebay" tabindex="-1"><a class="header-anchor" href="#_1-import-product-from-ebay"><span>1. Import Product from eBay</span></a></h3><p>Click on the Import product from ebay option to store product data in Magento database.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2023/09/mapproductlist.webp" alt="mapproduct"></p><p>Thus, after clicking the <strong>Import Product from the eBay</strong> option, the following pop-up window will appear. Now, you need to select the eBay listing end dates range for importing products.</p><p>So, select listing <strong>End Date\xA0From</strong>\xA0and <strong>End Date\xA0To</strong>.</p><p>The admin has the choice to select SKUs (comma separated):, by selecting the checkbox, this will enable only active products to be imported from eBay.</p><p>Hence, click <strong>Import Product from the eBay</strong> button as visible in the below screenshot.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2023/09/importproductfromebay.webp" alt="mapproductlist"></p><p>When the admin will click on “Import Product from eBay”, the product data will be created and stored in Magento 2 database.</p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/ebay-1.png" target="_blank" rel="noopener noreferrer">![image](https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/ebay-1.png)</a></p><h3 id="_2-run-ebay-product-profiler" tabindex="-1"><a class="header-anchor" href="#_2-run-ebay-product-profiler"><span>2. Run eBay Product Profiler</span></a></h3><p>You need to run the product profiler in order to create product entry in the Magento 2 catalog.</p><p>Hereafter completing the product profiler process, the imported products will be visible on the storefront immediately.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2023/09/mapproductlist-2.webp" alt="mapproductlist3"></p><p>Hence, when the admin will click on **Run eBay Product Profiler. **Henceforth the\xA0products will be created on Magento 2 store from Magento 2 Database (synchronized from eBay).</p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/download-3-.png" target="_blank" rel="noopener noreferrer">![eBay Connector for Magento 2](https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/download-3-.png)</a></p><h3 id="_3-run-ebay-product-image-profiler" tabindex="-1"><a class="header-anchor" href="#_3-run-ebay-product-image-profiler"><span>3. Run eBay product Image profiler</span></a></h3><p>Now you can run the product image profiler to import the product images in Magento 2.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2023/09/mapproductlist-3.webp" alt="mapproductlist"></p><p>Now, after running the profiler the imported product image will get displayed on the storefront. Hence the Images of the product will be created on Magento 2 store.</p><h3 id="_4-export-product-to-ebay" tabindex="-1"><a class="header-anchor" href="#_4-export-product-to-ebay"><span>4. Export Product to eBay</span></a></h3><p>Click on Export to eBay to export products from Magento 2 to ebay.</p><p>After clicking the <strong>Export to eBay</strong>, the admin will see a <strong>pop-up</strong> window.</p><p>Here, the admin can <strong>export all of the products</strong>\xA0(only visible products) to eBay by keeping the ** Product SKU** field <strong>empty.</strong></p><p>So, the admin can even <strong>export a single product</strong> by entering the **SKU of the product. **Henceforth clicking on\xA0the <strong>Export Product To eBay</strong> button.</p><p><em><strong>Note-</strong></em> Here visible products mean those products whose visibility is set as catalog, search; only catalog, or only search.</p><p>However, the products whose visibility is set as Not Visible Individually will not be exported.</p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/export-product-sku-1.png" target="_blank" rel="noopener noreferrer">![image](https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/export-product-sku-1.png)</a>After clicking the “<strong>Export Product to eBay</strong>“, you will see the below screen. Now, when\xA0the ** synchronization** is complete you can see the total number of products synced to eBay.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/exporting-message.png" alt="exporting message-eBay Connector for Magento2"></p><h3 id="export-via-catalog-product-grid" tabindex="-1"><a class="header-anchor" href="#export-via-catalog-product-grid"><span><strong>Export Via Catalog Product Grid</strong></span></a></h3><p>The admin can now export the products via the product grid in the admin panel. Thus, the admin can check the products for export.</p><p>Then in action, the admin can select <strong>Export to eBay.</strong></p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/catalog_export_product.png" target="_blank" rel="noopener noreferrer">![catalog_export_product_eBay Connector for Magento2](https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/catalog_export_product.png)</a></p><h3 id="ebay-product-information" tabindex="-1"><a class="header-anchor" href="#ebay-product-information"><span><strong>eBay Product Information</strong></span></a></h3><p>Please make sure you have provided all the necessary information for the exported products.</p><p>However, you will need to mention ** eBay specifications, conditions, and variations** (if any) in Magento products.</p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/eBay-Product-Visible.png" target="_blank" rel="noopener noreferrer">![eBay-Product-Visible- eBay Connector for Magento2](https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/eBay-Product-Visible.png)</a></p><p>**Please Note:\xA0**</p><ul><li>The product information like product name, images, price, description/content, and quantity can easily be Imported or Exported while product mapping on both stores.</li><li>Also, the Magento 2 eBay connector can synchronize product images for Simple as well as Configurable products.</li></ul><p>Hereafter exporting products to eBay, the admin can check the <strong>eBay store category</strong> to which the product has been assigned as per the category mapping.</p><p>For example, the admin has mapped his Magento 2 <strong>store category</strong>(having cameras) to eBay’s **Camera &amp; Photo **&gt; <strong>Camcorders</strong> sub-category.</p><p>Now, after the admin <strong>exports</strong> his product to **eBay **he can edit the imported product on eBay to check the product’s <strong>eBay store category</strong> according to the <strong>mapping</strong>.</p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/Product-Detail-Category.png" target="_blank" rel="noopener noreferrer">![eBay-Product-Visible-eBay Connector for Magento2](https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/Product-Detail-Category.png)</a></p><h3 id="bulk-action-assign-categories" tabindex="-1"><a class="header-anchor" href="#bulk-action-assign-categories"><span>Bulk Action- Assign Categories</span></a></h3><p>The admin can assign the categories in bulk to the products that were imported from eBay.</p><p>Herein, the admin needs to select the product and from the ‘Action’ dropdown can select the Assign To Category option.</p><p>Thus, this option will have a collection of Magento Categories that can be assigned.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2020/05/Assign-Category.png" alt="Assign-Category_eBay Connector for Magento2"></p><h3 id="bulk-migrate-listing" tabindex="-1"><a class="header-anchor" href="#bulk-migrate-listing"><span>Bulk Migrate Listing</span></a></h3><p>From the Sync From eBay dropdown, select Migrate Listing By ID to migrate specific eBay listings intothe Inventory API using their listing IDs.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2023/09/mapproductlist-5.webp" alt="mapproductlist"></p><p>From the Sync From eBay dropdown, select Migrate Listing By ID to migrate specific eBay listings intothe Inventory API using their listing IDs.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2023/09/migratelisting.webp" alt="migratelisting"></p><h3 id="export-queue-log" tabindex="-1"><a class="header-anchor" href="#export-queue-log"><span>Export Queue Log</span></a></h3><p>Navigate to eBay Magento Connect &gt; Export Queue Log to monitor the status of each queued product export.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2023/09/exportqueuelog.webp" alt="magento2_Ebaymagentoconnector_exportqueuelog"></p><p><strong>ID</strong> – Displays the unique identifier of the export queue record.</p><p><strong>Product SKU</strong> – Displays the SKU of the product queued for export.</p><p><strong>Product Name</strong> – Displays the name of the product being exported.</p><p><strong>Status</strong> – Displays the current export status such as Pending, Success, or Failed.</p><p><strong>eBay Item ID</strong> – Displays the eBay listing ID assigned after a successful export.</p><p><strong>Error Message</strong> – Displays the error details if the export process fails.</p><p><strong>Attempts</strong> – Displays the number of export attempts made for the product.</p><p><strong>Bulk Task ID</strong> – Displays the associated bulk export task ID when exported using the Feed API.</p><p><strong>Created At / Updated At</strong> – Displays when the export was queued and when it was last updated.</p><h3 id="bulk-export-tasks" tabindex="-1"><a class="header-anchor" href="#bulk-export-tasks"><span>Bulk Export Tasks</span></a></h3><p>When <strong>Use Bulk Feed API</strong> is enabled, the module exports products in batches using the eBay Sell Feed API.</p><p>Navigate to eBay Magento Connect &gt; Bulk Export Tasks to monitor bulk export jobs and their status.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2023/09/bulkexporttask.webp" alt="bulkexporttask"><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2023/09/exporttask.webp" alt="exporttask"></p><p><strong>ID</strong> – Displays the unique identifier of the bulk export task.</p><p><strong>eBay Task ID</strong> – Displays the task ID returned by the eBay Feed API.</p><p><strong>Feed Type</strong> – Displays the feed operation used for the bulk export.</p><p><strong>Status</strong> – Displays the current status of the bulk export task.</p><p><strong>Total Items</strong> – Displays the total number of products included in the batch.</p><p><strong>Success</strong> – Displays the number of products exported successfully.</p><p><strong>Failures</strong> – Displays the number of products that failed during export.</p><p><strong>Error Message</strong> – Displays the error details when a task fails.</p><p><strong>Result File</strong> – Provides the download link for the eBay result file.</p><p><strong>Created At / Updated At</strong> – Displays when the task was created and last updated.</p><p><strong>Note:</strong> The module creates bulk export tasks automatically and updates their status through scheduled cron jobs.</p><h2 id="listing-templates" tabindex="-1"><a class="header-anchor" href="#listing-templates"><span>Listing Templates</span></a></h2><p>The admin can add the listing templates by navigating through ** eBay Magento Connect**-&gt; <strong>Listing Templates</strong>.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/Listing-Templates-1.png" alt="image"></p><p>Thus, the admin can add a template by entering the title, content of the template in <strong>HTML</strong> or <strong>text</strong>. The admin can enable or disable a template.</p><p>Here, the admin has mapped the <strong>Magento Store Product Attributes</strong> to the <strong>Template variables</strong> that are being used within the listing template.</p><p>Now, when the admin creates the listing templates these <strong>template variables</strong> can be used within the template to send the respective item description data.<a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2019/03/webkul-magento2-ebay-connector-listing-template-title.png" target="_blank" rel="noopener noreferrer">![magento2 ebay connector](https://cdnblog.webkul.com/blog/wp-content/uploads/2019/03/webkul-magento2-ebay-connector-listing-template-title.png)</a></p><p>The admin can select product attributes and map them with the template variables so that the products can be exported to eBay with the listing template (item description).</p><p>After the products are imported you can see the template variable values on the product description and on the edit product page.<a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2019/03/webkul-magento2-ebay-connector-template-description.png" target="_blank" rel="noopener noreferrer">![eBay Connector for Magento2](https://cdnblog.webkul.com/blog/wp-content/uploads/2019/03/webkul-magento2-ebay-connector-template-description.png)</a></p><p>On the <strong>edit</strong> product page at <strong>eBay,</strong> you can see these values under the <strong>Item Description</strong> section.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/Item-Description-1.png" alt="image"></p><h2 id="price-rule" tabindex="-1"><a class="header-anchor" href="#price-rule"><span>Price Rule</span></a></h2><p>This section will help the admin to create a price rule which will be applied to the eBay product. The admin needs to navigate through <strong>Price Rule Tab</strong> in eBay Magento Connect Tab.<img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2023/09/ebaymagentoconnect-2.webp" alt="listing template"></p><p>On Price Rules For the eBay page, the admin can create multiple rules by clicking on <strong>Add Rule.</strong> However, the admin can even <strong>edit</strong> the previous price rule.</p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/download-8-.png" target="_blank" rel="noopener noreferrer">![image](https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/download-8-.png)</a></p><p>The price rule can be created by the admin by filling the following information-</p><ul><li>Product price From- Minimum price range of the products on which price rule will be applicable on eBay.</li><li>Product price To- Maximum\xA0price range of the products on which price rule will be applicable on eBay.</li><li>Operation Type- The admin can select the type of operation that will take place when price rule is applied that is if the price rule will follow the rule in the form of a percentage or fixed amount.</li><li>Operation- The action that will take place when the price rule is applied, that is the price of the product will increase or decrease.</li><li>Price- The admin can state here the amount which will be added or deducted from the product amount.</li><li>Status– The admin can enable or disable the status of the price rule.</li></ul><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/download-9-.png" target="_blank" rel="noopener noreferrer">![image](https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/download-9-.png)</a></p><h2 id="application-of-price-rule" tabindex="-1"><a class="header-anchor" href="#application-of-price-rule"><span>Application of Price Rule</span></a></h2><p><strong>When Admin has set ‘<em>eBay Price Rule Applicable For</em>‘ Export Products-</strong></p><p>For instance, we have a price rule of increase in price at a fixed rate of $2 with a price range of $1-$30. On Magento end, we create a product with a price of $24 as below.</p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/download-18-.png" target="_blank" rel="noopener noreferrer">![image_eBay Connector for Magento2](https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/download-18-.png)</a></p><p>Then as we export this product to eBay the price will automatically be incremented to $26 as per the rule.</p><p><a href="https://webkul.com/blog/ebay-connector-for-magento2/t-shirt-polo-ebay/" target="_blank" rel="noopener noreferrer">![eBay Connector for Magento 2](https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/T-shirt-Polo-eBay.png)</a></p><p>However, the same rule will act opposite if we import the same product from eBay to the Magento store.</p><p><em><strong>For example:</strong></em>\xA0If you have a product with $21 on eBay store and the price rule is set as\xA0of the increase in price at a fixed rate of $2 with a price range of $1-$30.</p><p>Now as we import the product to Magento store the price of the product at Magento end will be $19.</p><p><strong>When Admin has set ‘<em>eBay Price Rule Applicable For</em>‘ Import Products-</strong></p><p>Now the admin has the same price rule of increase in price at a fixed rate of $2 with a price range of $1-$30. The product is now on eBay at the price of $26 as given below.</p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/T-shirt-PoloXX-eBay.png" target="_blank" rel="noopener noreferrer">![image_eBay Connector for Magento2](https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/T-shirt-PoloXX-eBay.png)</a></p><p>Now, if the product gets imported the price of the product at the Magento store will be incremented by $2 as shown below.</p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/White-Tops.png" target="_blank" rel="noopener noreferrer">![image](https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/White-Tops.png)</a></p><p>Please notify here, the same rule will act opposite if we export the same product from eBay to Magento store.</p><p>For example, if you have a product with $26 and the price rule is set as\xA0of the increase in price at a fixed rate of $2 with a price range of $1-$30.</p><p>So as we import the product to eBay the price of the product at eBay end will be $24.</p><h2 id="ebay-specification-condition" tabindex="-1"><a class="header-anchor" href="#ebay-specification-condition"><span>Ebay Specification &amp; Condition</span></a></h2><p>At the time of Category mapping, eBay Product Condition and Specification will be created as Product attributes in Magento 2.</p><p>And these attributes label will be followed by eBay category name from where eBay condition and specification came.</p><p><strong>eBay-</strong></p><p><strong>Product Conditions</strong></p><p><strong><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/ebay-product-conditions.png" alt="image"></strong></p><p><strong>Specifications</strong></p><p>This option will come for every product in the back-end while editing or adding any new product. In eBay specification, admin can see various attributes with the label.</p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/ebay-specificaitions.png" target="_blank" rel="noopener noreferrer">![ebay specificaitions](https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/ebay-specificaitions.png)</a></p><h2 id="map-order" tabindex="-1"><a class="header-anchor" href="#map-order"><span>Map order</span></a></h2><p>Before synchronizing the orders from eBay to Magento 2, make sure that all products and its categories are synchronized from the eBay store to Magento 2 store.</p><p><strong>1. Import Order from eBay</strong></p><p>The admin can import the orders from the eBay store.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2023/09/ebay-orders-import.webp" alt="ebay-orders-import"></p><p>Here, the admin will click on “Import Order from eBay” tab, an eBay Order Range page will open as per the below image.</p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/IMPORT-ORDER.png" target="_blank" rel="noopener noreferrer">![image](https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/IMPORT-ORDER.png)</a></p><p>The admin will enter the date range. Proceed by clicking on <strong>Import Order from eBay</strong> and then orders will be imported from eBay to Magento 2 store.</p><p>So, only those orders will be imported from **eBay\xA0**to ** Magento 2\xA0**whose\xA0status is “<strong>Complete”</strong> on eBay.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2023/09/maped-ebay-order-list-process.webp" alt="maped-ebay-order-list-process"></p><p>Thus, if the eBay Product is not synced with Magento 2 store then the system will show an error.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2023/09/ebay-not-synced-products.webp" alt="ebay-not-synced-products"></p><p><strong>2. Run eBay Order Profiler</strong></p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/Map-eBay-Order.png" target="_blank" rel="noopener noreferrer">![Run eBay Order profiler](https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/Map-eBay-Order.png)</a></p><p>Now, the admin will click on <strong>Run eBay Order Profiler</strong>\xA0and orders from eBay will be imported and admin can see how much orders are imported and how many orders are left.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2023/09/importing-orders-from-ebay.webp" alt="importing-orders-from-ebay"></p><p>Hence the admin can get an error message if the eBay Order id is already mapped with Magento 2 Order id before running the profiler.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2023/09/ebay-already-maped-products.webp" alt="ebay-already-maped-products"></p><p>So, post importing the orders from eBay to Magento 2 store, the grid will look as per the below image.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2023/09/products-sync-from-ebay.webp" alt="products-sync-from-ebay"></p><p><strong>Note –</strong></p><ul><li>A cron is set which automatically imports the orders from the eBay store to Magento 2 store.\xA0 So, it also imports the products in the order, if they aren’t imported earlier.</li><li>For the imported orders when the admin process the shipments in Magento, tracking information is automatically synchronized to the corresponding eBay order in real-time. However, vice versa is not possible.</li></ul><h2 id="real-time-missed-order" tabindex="-1"><a class="header-anchor" href="#real-time-missed-order"><span>Real-Time Missed Order</span></a></h2><p>So, the information about the orders is displayed which could not import in real-time due to missing address details.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2020/05/real-time-missed-orders-1.png" alt="real-time-missed-orders-1"></p><h2 id="grouped-product-export-to-ebay" tabindex="-1"><a class="header-anchor" href="#grouped-product-export-to-ebay"><span>Grouped Product Export To eBay</span></a></h2><p>The Grouped product created on Magento 2 store can be easily exported to eBay. So, this can be done post creation of the grouped product on Magento 2 Store.</p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/download-12.png" target="_blank" rel="noopener noreferrer">![eBay Connector for Magento 2](https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/download-12.png)</a></p><p>After this admin needs to go to <strong>Map Product</strong> option. Thus, this will open a page **Mapped Products List, **where the admin can select ** Export to eBay.\xA0**</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/Ebay-Connector-blog-4.png" alt="Ebay-Connector-blog-4"></p><p>Thus, this export product can be seen on the eBay account under ** Sell&gt;All selling.**</p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/My-eBay-All-Selling.png" target="_blank" rel="noopener noreferrer">![image-eBay Connector for Magento2](https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/My-eBay-All-Selling.png)</a></p><p>Hence, on clicking the respective product you can find the product details on product page.</p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/download-13-.png" target="_blank" rel="noopener noreferrer">![image](https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/download-13-.png)</a></p><h2 id="bundle-products-export-to-ebay" tabindex="-1"><a class="header-anchor" href="#bundle-products-export-to-ebay"><span>Bundle Products Export to Ebay</span></a></h2><p>The bundle product created on Magento 2 store can be easily exported to eBay. Thus, this can be done post-creation of the bundle product on Magento 2 Store.</p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/bundledproducts.png" target="_blank" rel="noopener noreferrer">![bundledproducts](https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/bundledproducts.png)</a>After this admin needs to go to <strong>Map Product</strong> option, which will open a page\xA0**Mapped Products List, <strong>where admin can select ** Export to eBay.</strong></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/Ebay-Connector-blog-4-1.png" alt="Ebay-Connector-blog-4-1"></p><p>So, this exported product can be seen on the eBay account under ** Sell&gt;All selling.**</p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/My-eBay-All-Selling-1.png" target="_blank" rel="noopener noreferrer">![My eBay All Selling](https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/My-eBay-All-Selling-1.png)</a>So, on clicking the respective product you can find the product details on product page. Thus, the customer can select the products in the bundle to complete the bundle.</p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/Yoga-Kits-eBay.png" target="_blank" rel="noopener noreferrer">![Yoga Kits eBay](https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/Yoga-Kits-eBay.png)</a></p><h2 id="ebay-motors-integration" tabindex="-1"><a class="header-anchor" href="#ebay-motors-integration"><span>eBay Motors Integration</span></a></h2><p>The Magento 2 eBay Connector also works with <strong><a href="https://www.ebay.com/rpp/geo-parts-accessories-motors" target="_blank" rel="noopener noreferrer">eBay Motors</a></strong>. So, here we will show you how to set up eBay Motors integration with Magento 2.</p><p>Hereafter the successful connection, you will be able to synchronize products, categories. and orders from eBay to Magento 2 store.</p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2017/04/ebay-motors-homepage.png" target="_blank" rel="noopener noreferrer">![ebay motors homepage-eBay Connector for Magento2](https://cdnblog.webkul.com/blog/wp-content/uploads/2017/04/ebay-motors-homepage.png)</a></p><h3 id="steps" tabindex="-1"><a class="header-anchor" href="#steps"><span>Steps-</span></a></h3><h3 id="_1-–-module-configuration" tabindex="-1"><a class="header-anchor" href="#_1-–-module-configuration"><span>1 – Module Configuration</span></a></h3><p>Hence first, you need to go to <strong>Stores&gt; Configuration&gt; Webkul&gt; eBay Magento Connect</strong> and select the <strong>eBay Motors</strong> option in <strong>Global Sites</strong>.</p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/select-ebay-motors-options.png" target="_blank" rel="noopener noreferrer">![select ebay motors options_eBay Connector for Magento2](https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/select-ebay-motors-options.png)</a></p><h3 id="_2-–-import-ebay-motors-categories" tabindex="-1"><a class="header-anchor" href="#_2-–-import-ebay-motors-categories"><span>2 – Import eBay Motors Categories</span></a></h3><p>Hereafter, you need to import all the category information from eBay Motors to the Magento 2 store.</p><p>So, to do that go to the <strong>Import eBay Categories</strong> section and click the button.</p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/import-categories.png" target="_blank" rel="noopener noreferrer">![import categories](https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/import-categories.png)</a></p><p>Thus, a success message will appear after importing all the eBay categories.</p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/categories-import-message.png" target="_blank" rel="noopener noreferrer">![categories import message_eBay Connector for Magento2](https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/categories-import-message.png)</a></p><h3 id="_3-–-mapping-the-ebay-motors-category-with-the-store-category" tabindex="-1"><a class="header-anchor" href="#_3-–-mapping-the-ebay-motors-category-with-the-store-category"><span>3 – Mapping the eBay Motors category with the store category</span></a></h3><p>Now, you need to match the correct eBay Motors category with the store category one by one.</p><p>Thus, make sure you select the sub-category, you cannot map the parent category.</p><p>If mapping categories are not done correctly, products will not be synchronized properly.</p><p>So, to map a category go to <strong>eBay Magento Connect&gt;Map Category&gt;Map New Category.</strong></p><p>Hence following page will open, now select the store category and match it with the eBay category. Also, select the Magento attribute set according to the products.</p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/mapping-ebay-motors-categories.png" target="_blank" rel="noopener noreferrer">![mapping ebay motors categories](https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/mapping-ebay-motors-categories.png)</a></p><p>Thus, saving your mapped category information. It will get add to the mapped categories list.</p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/download-14-.png" target="_blank" rel="noopener noreferrer">![image](https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/download-14-.png)</a></p><h3 id="_4-–-importing-products-from-ebay-motors-to-magento-2" tabindex="-1"><a class="header-anchor" href="#_4-–-importing-products-from-ebay-motors-to-magento-2"><span>4 – Importing products from eBay Motors to Magento 2</span></a></h3><p>Now to import products from eBay Motors go to <strong>eBay Magento Connect&gt;Map Product&gt;Sync from eBay&gt;Import from eBay</strong>.</p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/import-from-ebay-button.png" target="_blank" rel="noopener noreferrer">![Ebay-Connector-blog-5](https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/Ebay-Connector-blog-5.png)</a></p><p>Select the date range for importing eBay products. Can even check if import only eBay Active Products. However, post that click Import Product from the eBay button.</p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/Mapped-Products-List-eBay-Magento-Connect-Magento-Admin-1.png" target="_blank" rel="noopener noreferrer">![image-eBay Connector for Magento2](https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/Mapped-Products-List-eBay-Magento-Connect-Magento-Admin-1.png)</a></p><p>Thus, you will get a pop-up message showing the number of products imported. So, next, you need to go to <strong>Sync from eBay</strong> option and select <strong>Run eBay Product Profiler</strong>.</p><p>So, this option will start adding the importing products to the Magento catalog.</p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/run-import-profiler.png" target="_blank" rel="noopener noreferrer">![run import profiler](https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/run-import-profiler.png)</a></p><p>Here is the sample product which got import from eBay Motors to Magento 2 store.</p><p><strong>eBay View</strong></p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/import-product-on-ebay-1.png" target="_blank" rel="noopener noreferrer">![import product on ebay](https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/import-product-on-ebay-1.png)</a></p><p><strong>Magento 2 View</strong></p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/imported-product-on-magento-2.png" target="_blank" rel="noopener noreferrer">![imported product on magento 2](https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/imported-product-on-magento-2.png)</a></p><p><strong>Mapped Product List</strong></p><p>Herein, the admin can view all the synchronized products list. Thus, it will show both imported as well as exported products.</p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/download-10-.png" target="_blank" rel="noopener noreferrer">![image](https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/download-10-.png)</a></p><h3 id="_5-–-exporting-products-from-magento-2-to-ebay-motors" tabindex="-1"><a class="header-anchor" href="#_5-–-exporting-products-from-magento-2-to-ebay-motors"><span>5 – Exporting products from Magento 2 to eBay Motors</span></a></h3><p>Now to export products go to **eBay Magento Connect&gt; Map Product&gt; Sync from eBay&gt; Import from eBay. **Hence a pop-up window will appear asking for product SKU.</p><p>Thus, Enter a product SKU or leave it blank.</p><p>However, if left blank all the Magento store products will get export to eBay Motors.</p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/export-product-sku-2.png" target="_blank" rel="noopener noreferrer">![image_eBay Connector for Magento2](https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/export-product-sku-2.png)</a></p><p>After clicking the <strong>Export Product to eBay</strong> button, the export profiler will run. So, it will start listing your products on eBay.</p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/exporting-message.png" target="_blank" rel="noopener noreferrer">![exporting message](https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/exporting-message.png)</a></p><p>So, here is the sample product that we have exported from Magento 2 to eBay Motors.</p><p><strong>Magento 2 store view</strong></p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/2017-08-09_17-17-09.png" target="_blank" rel="noopener noreferrer">![exported product eBay Connector for Magento2](https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/2017-08-09_17-17-09.png)</a></p><p><strong>eBay \xA0view</strong></p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/exported-product-on-ebay-view.png" target="_blank" rel="noopener noreferrer">![image_eBay Connector for Magento2](https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/exported-product-on-ebay-view.png)</a></p><p><strong>Exported product’s Shipping and Payment details</strong></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/shipping-and-payment-details.png" alt="eBay Connector for Magento2_image"></p><p>So, that’s all for eBay Connector for Magento 2 (Adobe Commerce) module if you still have any issues feel free to add a ticket and let us know your views to make the module better <a href="https://webkul.uvdesk.com/" target="_blank" rel="noopener noreferrer">webkul.uvdesk.com</a></p><p>Current Product Version - 4.0.8</p><p>Supported Framework Version - Magento 2.0.x, 2.1.x, 2.2.x,2.3.x, 2.4.x</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/11/nirupama-shree.webp" alt="author-thumb"></p><p><a href="https://webkul.com/blog/author/nirupama382/" target="_blank" rel="noopener noreferrer">nirupama shree 6 Badges</a></p><ul><li>17 Jun, 2026 Updated by - Ayush Tiwari</li><li>26 Sep, 2025 Updated by - Kush Mathur</li></ul><p>View More</p>`,402)]])}var s=r(a,[[`render`,o]]);export{i as _pageData,s as default};